+                store.check_or_insert(fill_key, &fill_payload, 1000, "cap-fill"),
+                DedupeResult::New
+            );
+        }
+        assert_eq!(store.entry_count(), MAX_DEDUPE_ENTRIES);
+
+        let retry = store.check_or_insert(key, payload, 1001, "cap-retry");
+        assert_eq!(retry, DedupeResult::New);
+        assert_eq!(store.entry_count(), MAX_DEDUPE_ENTRIES);
+    }
