+                DedupeResult::New
+            );
+        }
+        assert_eq!(store.entry_count(), MAX_DEDUPE_ENTRIES);
+
+        let replacement = store.check_or_insert(key, b"replacement", 1002, "cap-expired");
+        assert_eq!(replacement, DedupeResult::New);
+        assert_eq!(store.entry_count(), MAX_DEDUPE_ENTRIES);
+    }
